#pragma once\\\\n#include <cstdint>\\\\n#include <cstddef>\\\\n\\\\nvoid matmul(const float* A, const uint32_t* B, float* C, size_t M, size_t K) {\\\\n    for (size_t i = 0; i < M; ++i) {\\\\n        for (size_t j = 0; j < K; j += 32) {\\\\n            for (size_t k = 0; k < K; k += 32) {\\\\n                float sum = 0.0f;\\n                __m256vecA = _mm_loadu_ps(A + i * K + k);\\n                __m256vecB0 = _mm_loadu_ps(B + (j / 32) * (K/32) + k % 32);\\n                for (size_t p = 0; p < 32; p++) {\\\\n                    float bval = _mm_extract_ps(vecB0, p);\\\n                    float sgb = (bval >= 0.5f) ? 1.0f : -1.0f;\\\\n                    __m256 bvec = _mm_set1_ps(sgb);\\n                    __m256 prod = _mm_mul_ps(vecA, _mm_mul_ps(_mm_set1_ps(sgb), vecB0));\\n                    // Accumulate sum manually\\n                    __m256 sumAdd = _mm_add_ps(_mm_copy1_ps(sum), prod);\\n                    sum = _mm_ccopy1_ps(sum, sumAdd); // clamped sum update\\n                }\\n                __m256 sum_vec = _mm_set1_ps(sum);\\n                // Store partial result (for actual case, iterate across partial store)\\n                _mm_storeu_ps(&C[i * K + j], sum_vec);\\n            }\\n        }\\n    }\\n}